  "repo-ci/ci-node.yml": "# Dispatch CI gate — runs the repo's lint/test/build on every pull request so the\n# board's check-driven states reflect real results (Building → Ready to test →\n# Blocked). Each step runs only if the matching npm script exists, so this is\n# safe to drop into any Node/JS repo; adapt the steps for other stacks.\n#\n# NOTE: GitHub does not trigger workflows on events authored by GITHUB_TOKEN\n# (the github-actions[bot]). If claude-code-action opens PRs as the bot\n# (API-key-only setup), this gate will NOT run on those PRs. Install the Claude\n# GitHub App (/install-github-app) so PRs are app-authored and trigger CI.\nname: CI\non:\n  pull_request:\nconcurrency:\n  group: ci-${{ github.ref }}\n  cancel-in-progress: true\njobs:\n  test:\n    runs-on: ubuntu-latest\n    timeout-minutes: 15\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-node@v4\n        with:\n          node-version: \"20\"\n      - name: Install dependencies\n        run: npm ci || npm install\n      - name: Lint\n        run: npm run lint --if-present\n      - name: Test\n        run: npm run test --if-present\n      - name: Build\n        run: npm run build --if-present\n",
